        return {
            "modalities": ["text", "image"],
            "aspect_ratios": ["16:9", "9:16"],
            "min_duration": 1,
            "max_duration": 10,
        }

    def generate(self, prompt, *, image_url=None, model=None, **kwargs):
        endpoint = "image-to-video" if image_url else "text-to-video"
        # ... call API ...
        return success_response(
            video="https://cdn/out.mp4",
            model=model or "fast",
            prompt=prompt,
            modality="image" if image_url else "text",
            aspect_ratio="16:9",
            duration=5,
            provider=self.name,
        )

def register(ctx):
    ctx.register_video_gen_provider(MyVideoGenProvider())

